BEGIN;

CREATE SCHEMA IF NOT EXISTS "public";

CREATE TABLE "public"."tblAuthor" (
    "Author" TEXT,
    "AuthorCode" INTEGER,
    PRIMARY KEY ("AuthorCode")
);

CREATE TABLE "public"."tblCat" (
    "controlno" TEXT,
    "Title" TEXT,
    "Callno" TEXT,
    "AuthorCode" INTEGER,
    "Edition" TEXT,
    "Pagination" TEXT,
    "Publisher" TEXT,
    "Pubplace" TEXT,
    "Copyright" TEXT,
    "ISBN" TEXT,
    "Subject1Code" INTEGER,
    "Subject2Code" INTEGER,
    "Subject3Code" INTEGER,
    "SeriesTitle" TEXT,
    "AEntryTitle" TEXT,
    "AEAuthor1Code" INTEGER,
    "AEAuthor2Code" INTEGER,
    "AEAuthor3Code" INTEGER,
    "Material" TEXT,
    "xNotes" TEXT
);

CREATE TABLE "public"."tblFineCode" (
    "AmountPay" INTEGER,
    "Idno" TEXT,
    "dtePay" TIMESTAMP WITHOUT TIME ZONE,
    "Cashier" TEXT
);

CREATE TABLE "public"."tblGroup" (
    "Groupname" TEXT,
    "GrpFine" INTEGER,
    "GrpDuration" INTEGER,
    "GrpLimit" INTEGER
);

CREATE TABLE "public"."tblHoldings" (
    "controlno" TEXT,
    "Accession" TEXT,
    "Copy" TEXT,
    "Location" TEXT,
    "DueDate" TIMESTAMP WITHOUT TIME ZONE,
    "Status" TEXT
);

CREATE TABLE "public"."tblLocation" (
    "Location" TEXT,
    "LocCode" INTEGER,
    "LocationCode" INTEGER,
    "Allowed" INTEGER
);

CREATE TABLE "public"."tblMaterial" (
    "Material" TEXT
);

CREATE TABLE "public"."tblMessage" (
    "OpacMsg" TEXT
);

CREATE TABLE "public"."tblPassword" (
    "username" TEXT,
    "passwrd" TEXT,
    "usergroup" TEXT
);

CREATE TABLE "public"."tblRent" (
    "Accession" TEXT,
    "dteBorrow" TIMESTAMP WITHOUT TIME ZONE,
    "dteDue" TIMESTAMP WITHOUT TIME ZONE,
    "dteReturn" TIMESTAMP WITHOUT TIME ZONE,
    "FineCode" INTEGER,
    "Idno" TEXT
);

CREATE TABLE "public"."tblReserve" (
    "RecNumber" INTEGER,
    "Idno" TEXT,
    "Accession" TEXT,
    "DateReserve" TIMESTAMP WITHOUT TIME ZONE,
    "ReserveUntil" TIMESTAMP WITHOUT TIME ZONE,
    "IsServed" TEXT
);

CREATE TABLE "public"."tblSubject" (
    "subject" TEXT,
    "SubjectCode" INTEGER
);

CREATE TABLE "public"."tblUser" (
    "Name" TEXT,
    "Idno" TEXT,
    "GroupName" TEXT,
    "Expiry" TIMESTAMP WITHOUT TIME ZONE,
    "Dept" TEXT,
    "Phone" TEXT,
    "Email" TEXT,
    "UnpaidFine" INTEGER
);


